!function(){"use strict";Office.onReady(function(e){document.getElementById("get-data-from-selection").addEventListener("click",()=>{Office.context.document.getSelectedDataAsync?Office.context.document.getSelectedDataAsync(Office.CoercionType.Text,function(e){e.status===Office.AsyncResultStatus.Succeeded?document.getElementById("selected-data").textContent="Hello, world! The selected text is: "+e.value:(document.getElementById("selected-data").textContent="Error getting selected text.",console.error("Error:",e.error.message))}):(document.getElementById("selected-data").textContent="Error: Reading selection data isn't supported by this host application.",console.error("Error:","Reading selection data isn't supported by this host application."))})})}();